text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표",
        "decision": "스모크 테스트가 통과할 경우 공개 릴리스 목표 시각은 2026-05-15 15:00 KST이다.",
        "condition": "스모크 테스트 통과"
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인하고, 계약 자체가 잘못된 경우에만 script를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "기각"
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 릴리스",
        "detail": "2026-05-13은 내부 스트레치 목표일 뿐이며 최종 공개 릴리스 결정은 아니다."
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 절차 검토",
        "detail": "2026-05-14까지 가능하면 검토하자는 의견은 있었지만 담당자가 배정되지 않았다."
      },
      {
        "item": "릴리스 노트에 수요일 스트레치 목표를 언급할지 여부",
        "detail": "답이 결정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로",
        "impact": "릴리스가 지연될 수 있다."
      },
      {
        "risk": "README 설치 절차가 오래된 상태일 가능성",
        "impact": "릴리스 노트가 사용자를 오도할 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "미해결"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?",
        "status": "미해결"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "2026-05-15 10:00 KST",
      "status": "확정됨",
      "source_certainty": "명시적 확정"
    },
    {
      "owner": "Doyun",
      "task": "failure triage note를 action_items.md에 작성한다.",
      "due": "2026-05-15 12:00 KST",
      "status": "확정됨",
      "source_certainty": "명시적 확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 점검한다.",
      "due": "Minjun 결과 공유 이후, 정확한 마감 시각 미정",
      "status": "선행 결과 대기",
      "source_certainty": "명시적 확정"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 가능하면 검토한다.",
      "due": "2026-05-14 가능 시",
      "status": "담당자 미정",
      "source_certainty": "제안 수준"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "2026-05-15 10:00 KST까지 Minjun의 스모크 테스트 결과와 통과 여부를 확인한다.",
      "스모크 실패 또는 이슈 발생 시 Doyun의 triage note가 2026-05-15 12:00 KST까지 action_items.md에 기록되었는지 확인한다.",
      "Minjun의 결과 공유 이후 Hara의 tarball 경로 점검 결과를 확인한다.",
      "README 설치 절차 검토의 담당자 지정 여부와 실제 검토 완료 여부를 확인한다.",
      "최종 릴리스 승인 권한자와 릴리스 노트에 수요일 스트레치 목표를 넣을지 여부를 별도로 확정한다."
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "README 검토 담당자",
      "Hara 작업의 정확한 마감 시각"
    ]
  },
  "non_invention_rules": [
    "명시되지 않은 고객, 외부 파트너, 예산, 보안 사건, 장애, 법무 승인 사실을 추가하지 않는다.",
    "배정되지 않은 작업에는 임의로 owner를 넣지 않는다.",
    "정확한 마감이 없는 항목에는 임의 시각이나 날짜를 확정값처럼 쓰지 않는다.",
    "수요일 제안은 내부 스트레치 목표로만 기록하고 확정 공개 릴리스 결정으로 기록하지 않는다.",
    "기각된 제안은 확정 결정과 분리해서 기록한다.",
    "오픈 질문은 답이 정해진 것처럼 서술하지 않는다."
  ]
}
